// Chat Tool Use — agentic tool calling inside simplicio chat
// The LLM can request tool calls using [TOOL:name:args] syntax

use std::process::Command;

pub enum ChatTool {
    Shell,
    Read,
    Edit,
    Run,
}

impl ChatTool {
    pub fn all_descriptions() -> Vec<(&'static str, &'static str)> {
        vec![
            ("shell", "Run a shell command. Usage: [TOOL:shell:<command>]"),
            ("read", "Read file contents. Usage: [TOOL:read:<path>]"),
            ("edit", "Edit a file. Usage: [TOOL:edit:<path>|<old>|<new>]"),
            ("run", "Run a simplicio task. Usage: [TOOL:run:<task>]"),
        ]
    }

    pub fn execute(&self, args: &str) -> Result<String, String> {
        match self {
            ChatTool::Shell => Self::exec_shell(args),
            ChatTool::Read => Self::exec_read(args),
            ChatTool::Edit => Self::exec_edit(args),
            ChatTool::Run => Self::exec_run(args),
        }
    }

    fn exec_shell(cmd: &str) -> Result<String, String> {
        let output = Command::new("sh").arg("-c").arg(cmd).output()
            .map_err(|e| format!("shell failed: {e}"))?;
        let stdout = String::from_utf8_lossy(&output.stdout);
        let stderr = String::from_utf8_lossy(&output.stderr);
        Ok(format!("exit: {}\n{}\n{}",
            output.status.code().unwrap_or(-1),
            stdout, stderr))
    }

    fn exec_read(path: &str) -> Result<String, String> {
        let content = std::fs::read_to_string(path)
            .map_err(|e| format!("read failed: {e}"))?;
        Ok(format!("--- {} ---\n{}", path, content))
    }

    fn exec_edit(args: &str) -> Result<String, String> {
        let parts: Vec<&str> = args.splitn(3, '|').collect();
        if parts.len() < 3 {
            return Err("edit requires: path|old_text|new_text".into());
        }
        let content = std::fs::read_to_string(parts[0])
            .map_err(|e| format!("read failed: {e}"))?;
        let new_content = content.replace(parts[1], parts[2]);
        std::fs::write(parts[0], &new_content)
            .map_err(|e| format!("write failed: {e}"))?;
        Ok(format!("edited {} (1 replacement)", parts[0]))
    }

    fn exec_run(task: &str) -> Result<String, String> {
        let output = Command::new("simplicio").arg("run").arg(task)
            .arg("--repo").arg(".").arg("--json").output()
            .map_err(|e| format!("run failed: {e}"))?;
        let out = String::from_utf8_lossy(&output.stdout);
        Ok(format!("exit: {}\n{}",
            output.status.code().unwrap_or(-1), out))
    }
}

pub fn parse_tool_calls(text: &str) -> Vec<(String, String)> {
    let mut calls = Vec::new();
    let mut i = 0;
    let chars: Vec<char> = text.chars().collect();
    while i + 6 < chars.len() {
        if chars[i..i+6].iter().collect::<String>() == "[TOOL:" {
            if let Some(end) = text[i..].find("]") {
                let inner = &text[i+6..i+end];
                if let Some(colon) = inner.find(':') {
                    let name = inner[..colon].to_string();
                    let args = inner[colon+1..].to_string();
                    calls.push((name, args));
                }
                i += end + 1;
                continue;
            }
        }
        i += 1;
    }
    calls
}

pub fn execute_tool(name: &str, args: &str) -> String {
    let tool = match name {
        "shell" => ChatTool::Shell,
        "read" => ChatTool::Read,
        "edit" => ChatTool::Edit,
        "run" => ChatTool::Run,
        _ => return format!("Unknown tool: {name}"),
    };
    match tool.execute(args) {
        Ok(r) => format!("[TOOL RESULT:{}]\n{}\n[/TOOL RESULT]", name, r),
        Err(e) => format!("[TOOL ERROR:{}] {}", name, e),
    }
}
